// Nachricht verarbeiten: Sender + Text + Bild extrahieren
// Funktioniert für weitergeleitete UND direkte Nachrichten
const message = $('Telegram Trigger').item.json.message;
const isForwarded = !!message.forward_date;

let senderUsername = null;
let senderName = null;

if (isForwarded) {
  // WEITERGELEITET: Original-Absender extrahieren
  if (message.forward_from) {
    senderUsername = message.forward_from.username || null;
    senderName = [message.forward_from.first_name, message.forward_from.last_name].filter(Boolean).join(' ');
  }
  if (!senderUsername && message.forward_origin) {
    if (message.forward_origin.type === 'user' && message.forward_origin.sender_user) {
      senderUsername = message.forward_origin.sender_user.username || null;
      senderName = [message.forward_origin.sender_user.first_name, message.forward_origin.sender_user.last_name].filter(Boolean).join(' ');
    } else if (message.forward_origin.type === 'hidden_user') {
      senderName = message.forward_origin.sender_user_name || null;
    }
  }
  if (!senderUsername && message.forward_sender_name) {
    senderName = message.forward_sender_name;
  }
} else {
  // DIREKTE NACHRICHT: Absender = Chat-User
  senderUsername = message.from?.username || null;
  senderName = [message.from?.first_name, message.from?.last_name].filter(Boolean).join(' ');
}

// Bild erkennen: Telegram liefert ein Array von PhotoSize-Objekten
// Wir nehmen die größte Variante (letztes Element)
let photoFileId = null;
if (message.photo && message.photo.length > 0) {
  photoFileId = message.photo[message.photo.length - 1].file_id;
}

return {
  json: {
    sender_username: senderUsername,
    sender_name: senderName,
    message_text: message.text || message.caption || '',
    message_id: String(message.message_id),
    chat_id: message.chat.id,
    has_username: !!senderUsername,
    is_forwarded: isForwarded,
    photo_file_id: photoFileId,
    has_photo: !!photoFileId
  }
};

