// OpenAI Request MIT Bild bauen
const filePath = $input.item.json.result.file_path;
const botToken = '{{ $credentials.telegramApi.accessToken }}';
const imageUrl = `https://api.telegram.org/file/bot${botToken}/${filePath}`;
const messageText = $('Nachricht verarbeiten').item.json.message_text;

const systemPrompt = `Du extrahierst Event-Daten aus deutschen Telegram-Nachrichten und Event-Flyern/Bildern. Antworte ausschließlich als JSON mit diesen Feldern:
{
  "title": "Event-Titel",
  "description": "Beschreibung (max 500 Zeichen)",
  "start_at": "ISO 8601 mit Timezone Europe/Berlin, z.B. 2026-03-15T19:00:00+01:00",
  "end_at": "ISO 8601 oder null",
  "location_name": "Veranstaltungsort oder null",
  "address": "Vollständige Adresse oder null",
  "tags": ["tag1", "tag2"],
  "price_model": "free | paid | donation | null",
  "ticket_link": "URL oder null"
}

Regeln:
- Datum immer mit Timezone Europe/Berlin
- Wenn kein Jahr angegeben: 2026 annehmen
- Tags aus: meditation, yoga, breathwork, tanz, heilung, coaching, retreat, workshop, zeremonie, kakao, sound-healing, achtsamkeit
- Fehlende Felder als null
- Beschreibung zusammenfassen, nicht 1:1 kopieren
- Lies auch Text aus dem Bild/Flyer aus`;

const userContent = [];
if (messageText) {
  userContent.push({ type: 'text', text: messageText });
}
userContent.push({
  type: 'image_url',
  image_url: { url: imageUrl, detail: 'high' }
});

return {
  json: {
    model: 'gpt-4o-mini',
    temperature: 0.1,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userContent }
    ]
  }
};

// OpenAI Request NUR Text bauen
const messageText = $('Nachricht verarbeiten').item.json.message_text;

const systemPrompt = `Du extrahierst Event-Daten aus deutschen Telegram-Nachrichten. Antworte ausschließlich als JSON mit diesen Feldern:
{
  "title": "Event-Titel",
  "description": "Beschreibung (max 500 Zeichen)",
  "start_at": "ISO 8601 mit Timezone Europe/Berlin, z.B. 2026-03-15T19:00:00+01:00",
  "end_at": "ISO 8601 oder null",
  "location_name": "Veranstaltungsort oder null",
  "address": "Vollständige Adresse oder null",
  "tags": ["tag1", "tag2"],
  "price_model": "free | paid | donation | null",
  "ticket_link": "URL oder null"
}

Regeln:
- Datum immer mit Timezone Europe/Berlin
- Wenn kein Jahr angegeben: 2026 annehmen
- Tags aus: meditation, yoga, breathwork, tanz, heilung, coaching, retreat, workshop, zeremonie, kakao, sound-healing, achtsamkeit
- Fehlende Felder als null
- Beschreibung zusammenfassen, nicht 1:1 kopieren`;

return {
  json: {
    model: 'gpt-4o-mini',
    temperature: 0.1,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: messageText }
    ]
  }
};

// AI-Response parsen und Import-Payload bauen
const aiResponse = $input.item.json;
const choices = aiResponse.choices;

if (!choices || !choices.length) {
  throw new Error('Keine AI-Antwort erhalten');
}

const eventData = JSON.parse(choices[0].message.content);
const senderData = $('Nachricht verarbeiten').item.json;
const hostData = $('Host-Lookup').item.json;

// Telegram-Bild-URL zusammenbauen wenn vorhanden
let photoUrl = null;
if (senderData.has_photo) {
  try {
    const fileData = $('Bild-URL holen').item.json;
    if (fileData.result && fileData.result.file_path) {
      const botToken = '{{ $credentials.telegramApi.accessToken }}';
      photoUrl = `https://api.telegram.org/file/bot${botToken}/${fileData.result.file_path}`;
    }
  } catch (e) {
    // Kein Bild verfügbar
  }
}

return {
  json: {
    title: eventData.title,
    description: eventData.description,
    start_at: eventData.start_at,
    end_at: eventData.end_at,
    location_name: eventData.location_name,
    address: eventData.address,
    tags: eventData.tags || [],
    price_model: eventData.price_model,
    ticket_link: eventData.ticket_link,
    host_telegram_username: senderData.sender_username,
    sender_name: senderData.sender_name,
    source_message_id: 'tg_' + senderData.message_id,
    auto_publish: false,
    photo_url: photoUrl,
    chat_id: senderData.chat_id,
    host_name: hostData.host?.name || senderData.sender_name
  }
};

